import Procedure from './Procedure';
import Transition from './Transition';

/**
 * Each Activity corresponds to a single shape on a flow procedure diagram.
 * Activities are children of Procedures.
 * @class Activity
 * @memberof module:jibo-flow-core
 * @param {jibo.flow.Activity} activity Flow Activity to instantiate
 * @param {string} name Name of the activity
 * @param {string} id Internal uuid of the activity
 * @param {string} className Type of the activity (e.g. "Flow.Begin")
 * @param {string} assetPack Asset pack name if not within the project
 * @param {object} options Parameters required by the activity (e.g. "animPath")
 * @internal
 */

class Activity {
    public class:string;
    public assetPack: string;
    public id:string;
    public name:string;
    public procedure:Procedure;
    public transitions:Transition[];
    public exceptions:Transition[];
    public options:any;

    constructor(name:string, id:string, className:string, assetPack:string, options:any) {
        this.name = name;
        this.id = id;
        this.class = className;
        this.assetPack = assetPack;
        this.options = options;
    }

    
    set_transitions(transitions:Transition[]) {
        this.transitions = transitions;
    }
    
    set_exceptions(exceptions:Transition[]) {
        this.exceptions = exceptions;
    }
    
    set_procedure(procedure:Procedure) {
        this.procedure = procedure;
    }
}

export default Activity;
