import Activity from './Activity';
import Transition from './Transition';
import path = require('path');
import findRoot = require("find-root");

/**
 * A Procedure corresponds to one page of the Flow document, which corresponds to one .flow file.
 * It can be thought of as the in-memory representation of a .flow file.
 * Procedures are children of a FlowRoot.
 * @class Procedure
 * @memberof module:jibo-flow-core
 * @param {string} name Name of the procedure (e.g. "Main")
 * @param {string} uri Filename of the rocedure (e.g. "src/flows/Main.flow")
 * @param {any} local_inits Intializers for local (notepad) variables. Not currently in use.
 * @param {any} param_inits Default initializers for missing procedure parameters.
 * @internal
 */

class Procedure {
    public name:string;
    public uri:string;
    public relativeUri:string;
    public activities:{ [key:string]:Activity }; // indexed by id
    public local_inits:{ [key:string]:string };
    public param_inits:{ [key:string]:string };
    // The transitions (and exceptions) are indexed by the "from" node's activity-id
    // and return a list of outbound transitions (resp. exceptions) for that activity.
    public transitions:{ [key:string]:Transition[] };
    public exceptions:{ [key:string]:Transition[] };
    // This is a simple list of all the connections (transitions+exceptions) used in the procedure.
    public connections:Transition[];
    public procedureConstructor:any;
    public tree:any;

    constructor(name?:string, uri?:string, local_inits?:{[key:string]:string}, param_inits?:{[key:string]:string}) {
        this.name = name;
        this.uri = uri;
        this.activities = {};
        this.local_inits = local_inits;
        this.param_inits = param_inits;
        this.transitions = {};
        this.exceptions = {};
        this.connections = [];
    }

    /**
     * A helper function for the TreeLoader, it's how the
     * behavior tree-based flow representations are transformed into a Procedure flow-object.
     * @param {function} tree A function that is called when a Flow procedure is invoked that provides
     * all the JS objects (including functions wrapped in the procedure's namespace) referenced by the activities in the procedure.
     * There is one such a JS object for every option argument of every activity in the procedure, e.g. 'getConfig()'.
     */

    loadPropertiesFromTreeFunction(tree:any) {
        let treeObj = tree();
        for (let activityId in treeObj) {
            let t = treeObj[activityId];
            if (typeof t === 'function') {
                // No need to bind "this" here (needed when using the activity's options), we evaluate
                // the function now just to get access to the activity's static properties (e.g. name, id, class, etc.)
                t = t();
            }
            let activity = new Activity(t.name, t.id, t.class, t['asset-pack'], t.options);
            activity.transitions = t.transitions;
            activity.exceptions = t.exceptions;
            this.activities[t.id] = activity;
        }
        this.name = treeObj.meta.name;
        this.uri = treeObj.meta.uri;
        this.relativeUri = path.relative(findRoot('.'), this.uri);
        this.local_inits = {};
        this.param_inits = {};
        this.procedureConstructor = tree;
    }

    /**
     * Add a transition to the procedure.
     * NB. you must add all the transitions for the procedure first, then add the activities.
     * @param {jibo.flow.Transition} transition the transition to add to the procedure.
     */
    add_transition(transition:Transition) {
        let map = transition.value.startsWith('~') ? this.exceptions : this.transitions;
        if (!(transition.frm in map)) {
            map[transition.frm] = [];
        }
        map[transition.frm].push(transition);
        this.connections.push(transition);
    }

    /**
     * Add an activity to the procedure.
     * @param {jibo.flow.Activity} activity the activity to add to the procedure.
     */
    add_activity(activity:Activity) {
        let transitions = activity.id in this.transitions ? this.transitions[activity.id] : [];
        let exceptions = activity.id in this.exceptions ? this.exceptions[activity.id] : [];
        activity.set_transitions(transitions);
        activity.set_exceptions(exceptions);
        activity.set_procedure(this);
        this.activities[activity.id] = activity;
    }

    /**
     * Find the procedure's Flow.Begin activity.
     * @returns {jibo.flow.Activity}
     */
    getBeginActivity():Activity {
        for (let key in this.activities) {
            let activity = this.activities[key];
            if (activity.class === 'Flow.Begin') {
                return activity;
            }
        }
        throw new Error("No Flow.Begin Activity in procedure " + this.name);
    }

    /**
     * Find the procedure's Flow.Begin-Parallel activities.
     * @returns {Array} array of Flow.Begin-Parallel activities on the page.
     */
    getAsyncBeginActivities():Array<Activity> {
        let asyncs = [];
        for (let key in this.activities) {
            let activity = this.activities[key];
            if (activity.class === 'Flow.Begin-Parallel') {
                asyncs.push(activity);
            }
        }
        return asyncs;
    }

}

export default Procedure;
